4739 // Find the recipe with minimum alignment in the group.
4740 template <typename InstType>
4741 static VPReplicateRecipe *
4742 findRecipeWithMinAlign(ArrayRef<VPReplicateRecipe *> Group) {
4743   return *min_element(Group, [](VPReplicateRecipe *A, VPReplicateRecipe *B) {
4744     return cast<InstType>(A->getUnderlyingInstr())->getAlign() <
4745            cast<InstType>(B->getUnderlyingInstr())->getAlign();
4746   });
