4749 void VPlanTransforms::hoistPredicatedLoads(VPlan &Plan,
4750                                            PredicatedScalarEvolution &PSE,
4751                                            const Loop *L) {
4752   auto Groups =
4753       collectComplementaryPredicatedMemOps<Instruction::Load>(Plan, PSE, L);
4754   if (Groups.empty())
4755     return;
4756 
4757   // Process each group of loads.
4758   for (auto &Group : Groups) {
4759     // Try to use the earliest (most dominating) load to replace all others.
4760     VPReplicateRecipe *EarliestLoad = Group[0];
4761     VPBasicBlock *FirstBB = EarliestLoad->getParent();
4762     VPBasicBlock *LastBB = Group.back()->getParent();
4763 
4764     // Check that the load doesn't alias with stores between first and last.
4765     auto LoadLoc = vputils::getMemoryLocation(*EarliestLoad);
4766     if (!LoadLoc || !canHoistOrSinkWithNoAliasCheck(*LoadLoc, FirstBB, LastBB))
4767       continue;
4768 
4769     // Collect common metadata from all loads in the group.
4770     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4771 
4772     // Find the load with minimum alignment to use.
4773     auto *LoadWithMinAlign = findRecipeWithMinAlign<LoadInst>(Group);
4774 
4775     // Create an unpredicated version of the earliest load with common
4776     // metadata.
4777     auto *UnpredicatedLoad = new VPReplicateRecipe(
4778         LoadWithMinAlign->getUnderlyingInstr(), {EarliestLoad->getOperand(0)},
4779         /*IsSingleScalar=*/false, /*Mask=*/nullptr, *EarliestLoad,
4780         CommonMetadata);
4781 
4782     UnpredicatedLoad->insertBefore(EarliestLoad);
4783 
4784     // Replace all loads in the group with the unpredicated load.
4785     for (VPReplicateRecipe *Load : Group) {
4786       Load->replaceAllUsesWith(UnpredicatedLoad);
4787       Load->eraseFromParent();
4788     }
4789   }
