4907 void VPlanTransforms::materializePacksAndUnpacks(VPlan &Plan) {
4908   if (Plan.hasScalarVFOnly())
4909     return;
4910 
4911   VPTypeAnalysis TypeInfo(Plan);
4912   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
4913   auto VPBBsOutsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
4914       vp_depth_first_shallow(Plan.getEntry()));
4915   auto VPBBsInsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
4916       vp_depth_first_shallow(LoopRegion->getEntry()));
4917   // Materialize Build(Struct)Vector for all replicating VPReplicateRecipes and
4918   // VPInstructions, excluding ones in replicate regions. Those are not
4919   // materialized explicitly yet. Those vector users are still handled in
4920   // VPReplicateRegion::execute(), via shouldPack().
4921   // TODO: materialize build vectors for replicating recipes in replicating
4922   // regions.
4923   for (VPBasicBlock *VPBB :
4924        concat<VPBasicBlock *>(VPBBsOutsideLoopRegion, VPBBsInsideLoopRegion)) {
4925     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
4926       if (!isa<VPReplicateRecipe, VPInstruction>(&R))
4927         continue;
4928       auto *DefR = cast<VPRecipeWithIRFlags>(&R);
4929       auto UsesVectorOrInsideReplicateRegion = [DefR, LoopRegion](VPUser *U) {
4930         VPRegionBlock *ParentRegion = cast<VPRecipeBase>(U)->getRegion();
4931         return !U->usesScalars(DefR) || ParentRegion != LoopRegion;
4932       };
4933       if ((isa<VPReplicateRecipe>(DefR) &&
4934            cast<VPReplicateRecipe>(DefR)->isSingleScalar()) ||
4935           (isa<VPInstruction>(DefR) &&
4936            (vputils::onlyFirstLaneUsed(DefR) ||
4937             !cast<VPInstruction>(DefR)->doesGeneratePerAllLanes())) ||
4938           none_of(DefR->users(), UsesVectorOrInsideReplicateRegion))
4939         continue;
4940 
4941       Type *ScalarTy = TypeInfo.inferScalarType(DefR);
4942       unsigned Opcode = ScalarTy->isStructTy()
4943                             ? VPInstruction::BuildStructVector
4944                             : VPInstruction::BuildVector;
4945       auto *BuildVector = new VPInstruction(Opcode, {DefR});
4946       BuildVector->insertAfter(DefR);
4947 
4948       DefR->replaceUsesWithIf(
4949           BuildVector, [BuildVector, &UsesVectorOrInsideReplicateRegion](
4950                            VPUser &U, unsigned) {
4951             return &U != BuildVector && UsesVectorOrInsideReplicateRegion(&U);
4952           });
4953     }
4954   }
4955 
4956   // Create explicit VPInstructions to convert vectors to scalars. The current
4957   // implementation is conservative - it may miss some cases that may or may not
4958   // be vector values. TODO: introduce Unpacks speculatively - remove them later
4959   // if they are known to operate on scalar values.
4960   for (VPBasicBlock *VPBB : VPBBsInsideLoopRegion) {
4961     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
4962       if (isa<VPReplicateRecipe, VPInstruction, VPScalarIVStepsRecipe,
4963               VPDerivedIVRecipe, VPCanonicalIVPHIRecipe>(&R))
4964         continue;
4965       for (VPValue *Def : R.definedValues()) {
4966         // Skip recipes that are single-scalar or only have their first lane
4967         // used.
4968         // TODO: The Defs skipped here may or may not be vector values.
4969         // Introduce Unpacks, and remove them later, if they are guaranteed to
4970         // produce scalar values.
4971         if (vputils::isSingleScalar(Def) || vputils::onlyFirstLaneUsed(Def))
4972           continue;
4973 
4974         // At the moment, we create unpacks only for scalar users outside
4975         // replicate regions. Recipes inside replicate regions still extract the
4976         // required lanes implicitly.
4977         // TODO: Remove once replicate regions are unrolled completely.
4978         auto IsCandidateUnpackUser = [Def](VPUser *U) {
4979           VPRegionBlock *ParentRegion = cast<VPRecipeBase>(U)->getRegion();
4980           return U->usesScalars(Def) &&
4981                  (!ParentRegion || !ParentRegion->isReplicator());
4982         };
4983         if (none_of(Def->users(), IsCandidateUnpackUser))
4984           continue;
4985 
4986         auto *Unpack = new VPInstruction(VPInstruction::Unpack, {Def});
4987         if (R.isPhi())
4988           Unpack->insertBefore(*VPBB, VPBB->getFirstNonPhi());
4989         else
4990           Unpack->insertAfter(&R);
4991         Def->replaceUsesWithIf(Unpack,
4992                                [&IsCandidateUnpackUser](VPUser &U, unsigned) {
4993                                  return IsCandidateUnpackUser(&U);
4994                                });
4995       }
4996     }
4997   }
4998 }
