5000 void VPlanTransforms::materializeVectorTripCount(VPlan &Plan,
5001                                                  VPBasicBlock *VectorPHVPBB,
5002                                                  bool TailByMasking,
5003                                                  bool RequiresScalarEpilogue) {
5004   VPSymbolicValue &VectorTC = Plan.getVectorTripCount();
5005   // There's nothing to do if there are no users of the vector trip count or its
5006   // IR value has already been set.
5007   if (VectorTC.getNumUsers() == 0 || VectorTC.getUnderlyingValue())
5008     return;
5009 
5010   VPValue *TC = Plan.getTripCount();
5011   Type *TCTy = VPTypeAnalysis(Plan).inferScalarType(TC);
5012   VPBuilder Builder(VectorPHVPBB, VectorPHVPBB->begin());
5013   VPValue *Step = &Plan.getVFxUF();
5014 
5015   // If the tail is to be folded by masking, round the number of iterations N
5016   // up to a multiple of Step instead of rounding down. This is done by first
5017   // adding Step-1 and then rounding down. Note that it's ok if this addition
5018   // overflows: the vector induction variable will eventually wrap to zero given
5019   // that it starts at zero and its Step is a power of two; the loop will then
5020   // exit, with the last early-exit vector comparison also producing all-true.
5021   if (TailByMasking) {
5022     TC = Builder.createAdd(
5023         TC, Builder.createSub(Step, Plan.getConstantInt(TCTy, 1)),
5024         DebugLoc::getCompilerGenerated(), "n.rnd.up");
5025   }
5026 
5027   // Now we need to generate the expression for the part of the loop that the
5028   // vectorized body will execute. This is equal to N - (N % Step) if scalar
5029   // iterations are not required for correctness, or N - Step, otherwise. Step
5030   // is equal to the vectorization factor (number of SIMD elements) times the
5031   // unroll factor (number of SIMD instructions).
5032   VPValue *R =
5033       Builder.createNaryOp(Instruction::URem, {TC, Step},
5034                            DebugLoc::getCompilerGenerated(), "n.mod.vf");
5035 
5036   // There are cases where we *must* run at least one iteration in the remainder
5037   // loop.  See the cost model for when this can happen.  If the step evenly
5038   // divides the trip count, we set the remainder to be equal to the step. If
5039   // the step does not evenly divide the trip count, no adjustment is necessary
5040   // since there will already be scalar iterations. Note that the minimum
5041   // iterations check ensures that N >= Step.
5042   if (RequiresScalarEpilogue) {
5043     assert(!TailByMasking &&
5044            "requiring scalar epilogue is not supported with fail folding");
5045     VPValue *IsZero =
5046         Builder.createICmp(CmpInst::ICMP_EQ, R, Plan.getConstantInt(TCTy, 0));
5047     R = Builder.createSelect(IsZero, Step, R);
5048   }
5049 
5050   VPValue *Res =
5051       Builder.createSub(TC, R, DebugLoc::getCompilerGenerated(), "n.vec");
5052   VectorTC.replaceAllUsesWith(Res);
5053 }
