5055 void VPlanTransforms::materializeFactors(VPlan &Plan, VPBasicBlock *VectorPH,
5056                                          ElementCount VFEC) {
5057   VPBuilder Builder(VectorPH, VectorPH->begin());
5058   Type *TCTy = VPTypeAnalysis(Plan).inferScalarType(Plan.getTripCount());
5059   VPValue &VF = Plan.getVF();
5060   VPValue &VFxUF = Plan.getVFxUF();
5061   // Note that after the transform, no further uses of Plan.getVF and
5062   // Plan.getVFxUF should be added.
5063   // TODO: Add assertions for this.
5064 
5065   // If there are no users of the runtime VF, compute VFxUF by constant folding
5066   // the multiplication of VF and UF.
5067   if (VF.getNumUsers() == 0) {
5068     VPValue *RuntimeVFxUF =
5069         Builder.createElementCount(TCTy, VFEC * Plan.getConcreteUF());
5070     VFxUF.replaceAllUsesWith(RuntimeVFxUF);
5071     return;
5072   }
5073 
5074   // For users of the runtime VF, compute it as VF * vscale, and VFxUF as (VF *
5075   // vscale) * UF.
5076   VPValue *RuntimeVF = Builder.createElementCount(TCTy, VFEC);
5077   if (!vputils::onlyScalarValuesUsed(&VF)) {
5078     VPValue *BC = Builder.createNaryOp(VPInstruction::Broadcast, RuntimeVF);
5079     VF.replaceUsesWithIf(
5080         BC, [&VF](VPUser &U, unsigned) { return !U.usesScalars(&VF); });
5081   }
5082   VF.replaceAllUsesWith(RuntimeVF);
5083 
5084   VPValue *MulByUF = Builder.createOverflowingOp(
5085       Instruction::Mul,
5086       {RuntimeVF, Plan.getConstantInt(TCTy, Plan.getConcreteUF())},
5087       {true, false});
5088   VFxUF.replaceAllUsesWith(MulByUF);
5089 }
