5092 VPlanTransforms::expandSCEVs(VPlan &Plan, ScalarEvolution &SE) {
5093   SCEVExpander Expander(SE, "induction", /*PreserveLCSSA=*/false);
5094 
5095   auto *Entry = cast<VPIRBasicBlock>(Plan.getEntry());
5096   BasicBlock *EntryBB = Entry->getIRBasicBlock();
5097   DenseMap<const SCEV *, Value *> ExpandedSCEVs;
5098   for (VPRecipeBase &R : make_early_inc_range(*Entry)) {
5099     if (isa<VPIRInstruction, VPIRPhi>(&R))
5100       continue;
5101     auto *ExpSCEV = dyn_cast<VPExpandSCEVRecipe>(&R);
5102     if (!ExpSCEV)
5103       break;
5104     const SCEV *Expr = ExpSCEV->getSCEV();
5105     Value *Res =
5106         Expander.expandCodeFor(Expr, Expr->getType(), EntryBB->getTerminator());
5107     ExpandedSCEVs[ExpSCEV->getSCEV()] = Res;
5108     VPValue *Exp = Plan.getOrAddLiveIn(Res);
5109     ExpSCEV->replaceAllUsesWith(Exp);
5110     if (Plan.getTripCount() == ExpSCEV)
5111       Plan.resetTripCount(Exp);
5112     ExpSCEV->eraseFromParent();
5113   }
5114   assert(none_of(*Entry, IsaPred<VPExpandSCEVRecipe>) &&
5115          "VPExpandSCEVRecipes must be at the beginning of the entry block, "
5116          "before any VPIRInstructions");
5117   // Add IR instructions in the entry basic block but not in the VPIRBasicBlock
5118   // to the VPIRBasicBlock.
5119   auto EI = Entry->begin();
5120   for (Instruction &I : drop_end(*EntryBB)) {
5121     if (EI != Entry->end() && isa<VPIRInstruction>(*EI) &&
5122         &cast<VPIRInstruction>(&*EI)->getInstruction() == &I) {
5123       EI++;
5124       continue;
5125     }
5126     VPIRInstruction::create(I)->insertBefore(*Entry, EI);
5127   }
5128 
5129   return ExpandedSCEVs;
5130 }
