414 // Merge replicate regions in their successor region, if a replicate region
415 // is connected to a successor replicate region with the same predicate by a
416 // single, empty VPBasicBlock.
417 static bool mergeReplicateRegionsIntoSuccessors(VPlan &Plan) {
418   SmallPtrSet<VPRegionBlock *, 4> TransformedRegions;
419 
420   // Collect replicate regions followed by an empty block, followed by another
421   // replicate region with matching masks to process front. This is to avoid
422   // iterator invalidation issues while merging regions.
423   SmallVector<VPRegionBlock *, 8> WorkList;
424   for (VPRegionBlock *Region1 : VPBlockUtils::blocksOnly<VPRegionBlock>(
425            vp_depth_first_deep(Plan.getEntry()))) {
426     if (!Region1->isReplicator())
427       continue;
428     auto *MiddleBasicBlock =
429         dyn_cast_or_null<VPBasicBlock>(Region1->getSingleSuccessor());
430     if (!MiddleBasicBlock || !MiddleBasicBlock->empty())
431       continue;
432 
433     auto *Region2 =
434         dyn_cast_or_null<VPRegionBlock>(MiddleBasicBlock->getSingleSuccessor());
435     if (!Region2 || !Region2->isReplicator())
436       continue;
437 
438     VPValue *Mask1 = getPredicatedMask(Region1);
439     VPValue *Mask2 = getPredicatedMask(Region2);
440     if (!Mask1 || Mask1 != Mask2)
441       continue;
442 
443     assert(Mask1 && Mask2 && "both region must have conditions");
444     WorkList.push_back(Region1);
445   }
446 
447   // Move recipes from Region1 to its successor region, if both are triangles.
448   for (VPRegionBlock *Region1 : WorkList) {
449     if (TransformedRegions.contains(Region1))
450       continue;
451     auto *MiddleBasicBlock = cast<VPBasicBlock>(Region1->getSingleSuccessor());
452     auto *Region2 = cast<VPRegionBlock>(MiddleBasicBlock->getSingleSuccessor());
453 
454     VPBasicBlock *Then1 = getPredicatedThenBlock(Region1);
455     VPBasicBlock *Then2 = getPredicatedThenBlock(Region2);
456     if (!Then1 || !Then2)
457       continue;
458 
459     // Note: No fusion-preventing memory dependencies are expected in either
460     // region. Such dependencies should be rejected during earlier dependence
461     // checks, which guarantee accesses can be re-ordered for vectorization.
462     //
463     // Move recipes to the successor region.
464     for (VPRecipeBase &ToMove : make_early_inc_range(reverse(*Then1)))
465       ToMove.moveBefore(*Then2, Then2->getFirstNonPhi());
466 
467     auto *Merge1 = cast<VPBasicBlock>(Then1->getSingleSuccessor());
468     auto *Merge2 = cast<VPBasicBlock>(Then2->getSingleSuccessor());
469 
470     // Move VPPredInstPHIRecipes from the merge block to the successor region's
471     // merge block. Update all users inside the successor region to use the
472     // original values.
473     for (VPRecipeBase &Phi1ToMove : make_early_inc_range(reverse(*Merge1))) {
474       VPValue *PredInst1 =
475           cast<VPPredInstPHIRecipe>(&Phi1ToMove)->getOperand(0);
476       VPValue *Phi1ToMoveV = Phi1ToMove.getVPSingleValue();
477       Phi1ToMoveV->replaceUsesWithIf(PredInst1, [Then2](VPUser &U, unsigned) {
478         return cast<VPRecipeBase>(&U)->getParent() == Then2;
479       });
480 
481       // Remove phi recipes that are unused after merging the regions.
482       if (Phi1ToMove.getVPSingleValue()->getNumUsers() == 0) {
483         Phi1ToMove.eraseFromParent();
484         continue;
485       }
486       Phi1ToMove.moveBefore(*Merge2, Merge2->begin());
487     }
488 
489     // Remove the dead recipes in Region1's entry block.
490     for (VPRecipeBase &R :
491          make_early_inc_range(reverse(*Region1->getEntryBasicBlock())))
492       R.eraseFromParent();
493 
494     // Finally, remove the first region.
495     for (VPBlockBase *Pred : make_early_inc_range(Region1->getPredecessors())) {
496       VPBlockUtils::disconnectBlocks(Pred, Region1);
497       VPBlockUtils::connectBlocks(Pred, MiddleBasicBlock);
498     }
499     VPBlockUtils::disconnectBlocks(Region1, MiddleBasicBlock);
500     TransformedRegions.insert(Region1);
501   }
