4688   // For each address, collect operations with the same or complementary masks.
4689   SmallVector<SmallVector<VPReplicateRecipe *, 4>> AllGroups;
4690   auto GetLoadStoreValueType = [&](VPReplicateRecipe *Recipe) {
4691     return TypeInfo.inferScalarType(IsLoad ? Recipe : Recipe->getOperand(0));
4692   };
4693   auto Groups = collectGroupedReplicateMemOps<Opcode>(
4694       Plan, PSE, L,
4695       [](VPReplicateRecipe *RepR) { return RepR->isPredicated(); });
4696   for (auto Recipes : Groups) {
4697     if (Recipes.size() < 2)
4698       continue;
4699 
4700     // Collect groups with the same or complementary masks.
4701     for (VPReplicateRecipe *&RecipeI : Recipes) {
4702       if (!RecipeI)
4703         continue;
4704 
4705       VPValue *MaskI = RecipeI->getMask();
4706       Type *TypeI = GetLoadStoreValueType(RecipeI);
4707       SmallVector<VPReplicateRecipe *, 4> Group;
4708       Group.push_back(RecipeI);
4709       RecipeI = nullptr;
4710 
4711       // Find all operations with the same or complementary masks.
4712       bool HasComplementaryMask = false;
4713       for (VPReplicateRecipe *&RecipeJ : Recipes) {
4714         if (!RecipeJ)
4715           continue;
4716 
4717         VPValue *MaskJ = RecipeJ->getMask();
4718         Type *TypeJ = GetLoadStoreValueType(RecipeJ);
4719         if (TypeI == TypeJ) {
4720           // Check if any operation in the group has a complementary mask with
4721           // another, that is M1 == NOT(M2) or M2 == NOT(M1).
4722           HasComplementaryMask |= match(MaskI, m_Not(m_Specific(MaskJ))) ||
4723                                   match(MaskJ, m_Not(m_Specific(MaskI)));
4724           Group.push_back(RecipeJ);
4725           RecipeJ = nullptr;
4726         }
4727       }
4728 
4729       if (HasComplementaryMask) {
4730         assert(Group.size() >= 2 && "must have at least 2 entries");
4731         AllGroups.push_back(std::move(Group));
4732       }
4733     }
4734   }
4735 
4736   return AllGroups;
4737 }
4738 
4739 // Find the recipe with minimum alignment in the group.
4740 template <typename InstType>
4741 static VPReplicateRecipe *
4742 findRecipeWithMinAlign(ArrayRef<VPReplicateRecipe *> Group) {
4743   return *min_element(Group, [](VPReplicateRecipe *A, VPReplicateRecipe *B) {
4744     return cast<InstType>(A->getUnderlyingInstr())->getAlign() <
4745            cast<InstType>(B->getUnderlyingInstr())->getAlign();
4746   });
4747 }
4748 
4749 void VPlanTransforms::hoistPredicatedLoads(VPlan &Plan,
4750                                            PredicatedScalarEvolution &PSE,
4751                                            const Loop *L) {
4752   auto Groups =
4753       collectComplementaryPredicatedMemOps<Instruction::Load>(Plan, PSE, L);
4754   if (Groups.empty())
4755     return;
4756 
4757   // Process each group of loads.
4758   for (auto &Group : Groups) {
4759     // Try to use the earliest (most dominating) load to replace all others.
4760     VPReplicateRecipe *EarliestLoad = Group[0];
4761     VPBasicBlock *FirstBB = EarliestLoad->getParent();
4762     VPBasicBlock *LastBB = Group.back()->getParent();
4763 
4764     // Check that the load doesn't alias with stores between first and last.
4765     auto LoadLoc = vputils::getMemoryLocation(*EarliestLoad);
4766     if (!LoadLoc || !canHoistOrSinkWithNoAliasCheck(*LoadLoc, FirstBB, LastBB))
4767       continue;
4768 
4769     // Collect common metadata from all loads in the group.
4770     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4771 
4772     // Find the load with minimum alignment to use.
4773     auto *LoadWithMinAlign = findRecipeWithMinAlign<LoadInst>(Group);
4774 
4775     // Create an unpredicated version of the earliest load with common
4776     // metadata.
4777     auto *UnpredicatedLoad = new VPReplicateRecipe(
4778         LoadWithMinAlign->getUnderlyingInstr(), {EarliestLoad->getOperand(0)},
4779         /*IsSingleScalar=*/false, /*Mask=*/nullptr, *EarliestLoad,
4780         CommonMetadata);
4781 
4782     UnpredicatedLoad->insertBefore(EarliestLoad);
4783 
4784     // Replace all loads in the group with the unpredicated load.
4785     for (VPReplicateRecipe *Load : Group) {
4786       Load->replaceAllUsesWith(UnpredicatedLoad);
4787       Load->eraseFromParent();
4788     }
4789   }
4790 }
4791 
4792 static bool
4793 canSinkStoreWithNoAliasCheck(ArrayRef<VPReplicateRecipe *> StoresToSink,
4794                              PredicatedScalarEvolution &PSE, const Loop &L,
4795                              VPTypeAnalysis &TypeInfo) {
4796   auto StoreLoc = vputils::getMemoryLocation(*StoresToSink.front());
4797   if (!StoreLoc || !StoreLoc->AATags.Scope)
4798     return false;
4799 
4800   // When sinking a group of stores, all members of the group alias each other.
4801   // Skip them during the alias checks.
4802   SmallPtrSet<VPRecipeBase *, 4> StoresToSinkSet(StoresToSink.begin(),
4803                                                  StoresToSink.end());
4804 
4805   VPBasicBlock *FirstBB = StoresToSink.front()->getParent();
4806   VPBasicBlock *LastBB = StoresToSink.back()->getParent();
4807   SinkStoreInfo SinkInfo(StoresToSinkSet, *StoresToSink[0], PSE, L, TypeInfo);
4808   return canHoistOrSinkWithNoAliasCheck(*StoreLoc, FirstBB, LastBB, SinkInfo);
4809 }
4810 
4811 void VPlanTransforms::sinkPredicatedStores(VPlan &Plan,
4812                                            PredicatedScalarEvolution &PSE,
4813                                            const Loop *L) {
4814   auto Groups =
4815       collectComplementaryPredicatedMemOps<Instruction::Store>(Plan, PSE, L);
4816   if (Groups.empty())
4817     return;
4818 
4819   VPTypeAnalysis TypeInfo(Plan);
4820 
4821   for (auto &Group : Groups) {
4822     if (!canSinkStoreWithNoAliasCheck(Group, PSE, *L, TypeInfo))
4823       continue;
4824 
4825     // Use the last (most dominated) store's location for the unconditional
4826     // store.
4827     VPReplicateRecipe *LastStore = Group.back();
4828     VPBasicBlock *InsertBB = LastStore->getParent();
4829 
4830     // Collect common alias metadata from all stores in the group.
4831     VPIRMetadata CommonMetadata = getCommonMetadata(Group);
4832 
4833     // Build select chain for stored values.
4834     VPValue *SelectedValue = Group[0]->getOperand(0);
4835     VPBuilder Builder(InsertBB, LastStore->getIterator());
4836 
4837     bool IsSingleScalar = Group[0]->isSingleScalar();
4838     for (unsigned I = 1; I < Group.size(); ++I) {
4839       assert(IsSingleScalar == Group[I]->isSingleScalar() &&
4840              "all members in group must agree on IsSingleScalar");
4841       VPValue *Mask = Group[I]->getMask();
4842       VPValue *Value = Group[I]->getOperand(0);
4843       SelectedValue = Builder.createSelect(Mask, Value, SelectedValue,
4844                                            Group[I]->getDebugLoc());
4845     }
4846 
4847     // Find the store with minimum alignment to use.
4848     auto *StoreWithMinAlign = findRecipeWithMinAlign<StoreInst>(Group);
4849 
4850     // Create unconditional store with selected value and common metadata.
4851     auto *UnpredicatedStore = new VPReplicateRecipe(
4852         StoreWithMinAlign->getUnderlyingInstr(),
4853         {SelectedValue, LastStore->getOperand(1)}, IsSingleScalar,
4854         /*Mask=*/nullptr, *LastStore, CommonMetadata);
4855     UnpredicatedStore->insertBefore(*InsertBB, LastStore->getIterator());
4856 
4857     // Remove all predicated stores from the group.
4858     for (VPReplicateRecipe *Store : Group)
4859       Store->eraseFromParent();
4860   }
4861 }
