4863 void VPlanTransforms::materializeConstantVectorTripCount(
4864     VPlan &Plan, ElementCount BestVF, unsigned BestUF,
4865     PredicatedScalarEvolution &PSE) {
4866   assert(Plan.hasVF(BestVF) && "BestVF is not available in Plan");
4867   assert(Plan.hasUF(BestUF) && "BestUF is not available in Plan");
4868 
4869   VPValue *TC = Plan.getTripCount();
4870   // Skip cases for which the trip count may be non-trivial to materialize.
4871   // I.e., when a scalar tail is absent - due to tail folding, or when a scalar
4872   // tail is required.
4873   if (!Plan.hasScalarTail() ||
4874       Plan.getMiddleBlock()->getSingleSuccessor() ==
4875           Plan.getScalarPreheader() ||
4876       !isa<VPIRValue>(TC))
4877     return;
4878 
4879   // Materialize vector trip counts for constants early if it can simply
4880   // be computed as (Original TC / VF * UF) * VF * UF.
4881   // TODO: Compute vector trip counts for loops requiring a scalar epilogue and
4882   // tail-folded loops.
4883   ScalarEvolution &SE = *PSE.getSE();
4884   auto *TCScev = SE.getSCEV(TC->getLiveInIRValue());
4885   if (!isa<SCEVConstant>(TCScev))
4886     return;
4887   const SCEV *VFxUF = SE.getElementCount(TCScev->getType(), BestVF * BestUF);
4888   auto VecTCScev = SE.getMulExpr(SE.getUDivExpr(TCScev, VFxUF), VFxUF);
